<template><div class="grid"><section class="galaxy-card span5"><h3 class="section-title">声音质量评价</h3><el-form label-position="top" class="form-grid"><el-form-item label="声音模型"><el-select v-model="form.voice_model_id" style="width:100%"><el-option v-for="v in voices" :key="v.id" :label="v.name" :value="v.id" /></el-select></el-form-item><el-form-item label="评分"><el-rate v-model="form.rating" show-score /></el-form-item><el-form-item label="评论"><el-input v-model="form.comment" type="textarea" :rows="7" /></el-form-item><el-button type="primary" size="large" @click="submit">提交评价</el-button></el-form></section><section class="galaxy-card span7"><h3 class="section-title">历史评价</h3><div v-for="f in feedbacks" :key="f.id" class="script-card"><el-rate :model-value="f.rating" disabled /><p>{{f.comment}}</p><p class="muted">{{f.created_at||f.createdAt}}</p></div></section></div></template>
<script setup>import { reactive,ref,onMounted } from 'vue';import { ElMessage } from 'element-plus';import { getVoiceList } from '@/api/voice';import { getFeedbackList,submitFeedback } from '@/api/feedback';const voices=ref([]),feedbacks=ref([]);const form=reactive({voice_model_id:null,rating:5,comment:''});async function load(){voices.value=await getVoiceList();feedbacks.value=await getFeedbackList();form.voice_model_id=form.voice_model_id||voices.value[0]?.id}onMounted(load);async function submit(){await submitFeedback(form);ElMessage.success('感谢反馈');form.comment='';load()}</script>
